using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// Options with the default reflection-based resolver (resolves any type)
var options = new JsonSerializerOptions(JsonSerializerDefaults.Web);

// 1️⃣ GetTypeInfo<T>() — returns a strongly-typed JsonTypeInfo<T>
JsonTypeInfo<Person> personInfo = options.GetTypeInfo<Person>();
Console.WriteLine($"GetTypeInfo<Person> returned type: {personInfo.Type.Name}");

string json = JsonSerializer.Serialize(new Person("Alice", 42), personInfo);
Console.WriteLine($"Serialized: {json}");

// 2️⃣ TryGetTypeInfo<T>() — probe without throwing
if (options.TryGetTypeInfo<Person>(out JsonTypeInfo<Person>? info))
{
    Console.WriteLine($"TryGetTypeInfo<Person> succeeded: {info!.Type.Name}");
}

// Now demonstrate a case where metadata is NOT available.
// Use a custom resolver that only knows about Person.
var limited = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
        .WithAddedModifier(ti =>
        {
            // Artificially reject everything except Person
            if (ti.Type != typeof(Person))
                ti.CreateObject = null; // still "resolves" — let's use a wrapper instead
        })
};

// A truly restrictive resolver: one that returns null for unknown types
var strict = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine(
        new PersonOnlyResolver())
};

if (strict.TryGetTypeInfo<int>(out JsonTypeInfo<int>? intInfo))
{
    Console.WriteLine($"Unexpected: got type info for int");
}
else
{
    Console.WriteLine("TryGetTypeInfo<int> returned false — no metadata available (no exception thrown)");
}

Console.WriteLine("Done.");

